import React, { useState, useEffect, useRef } from 'react';
import { Page, Article, Author, NovusMessage } from './types';
import { getArticles } from './api/cms';
import { GoogleGenAI } from '@google/genai';

import Layout from './components/layout/Layout';
import Hero from './components/Hero';
import Mission from './components/About';
import Articles from './components/Articles';
import ArticlePage from './components/articles/ArticlePage';
import AuthorPage from './components/author/AuthorPage';
import GlobalTrending from './components/GlobalTrending';
import Ecosystem from './components/Ecosystem';
import Contact from './components/Contact';
import Chatbot from './components/Chatbot';

const App: React.FC = () => {
    const [activePage, setActivePage] = useState<Page>(Page.Home);
    const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
    const [selectedAuthor, setSelectedAuthor] = useState<Author | null>(null);
    const [searchQuery, setSearchQuery] = useState('');

    const [allArticles, setAllArticles] = useState<Article[]>([]);
    const [articlesLoading, setArticlesLoading] = useState<boolean>(true);
    const [filteredArticles, setFilteredArticles] = useState<Article[]>([]);

    const [isChatbotOpen, setIsChatbotOpen] = useState(false);
    const [messages, setMessages] = useState<NovusMessage[]>([
        { id: 0, source: 'model', text: "Hello! I'm Novus, your AI research assistant. Ask me anything about our articles, global trends, or other complex topics." }
    ]);

    // Refs for sections
    const sectionRefs = {
        [Page.Home]: useRef<HTMLDivElement>(null),
        [Page.Mission]: useRef<HTMLDivElement>(null),
        [Page.Articles]: useRef<HTMLDivElement>(null),
        [Page.GlobalTrending]: useRef<HTMLDivElement>(null),
        [Page.Ecosystem]: useRef<HTMLDivElement>(null),
        [Page.Contact]: useRef<HTMLDivElement>(null),
    };

    useEffect(() => {
        const loadArticles = async () => {
            try {
                setArticlesLoading(true);
                const articles = await getArticles();
                setAllArticles(articles);
            } catch (error) {
                console.error("Failed to load articles:", error);
            } finally {
                setArticlesLoading(false);
            }
        };
        loadArticles();
    }, []);

    useEffect(() => {
        const lowercasedQuery = searchQuery.toLowerCase().trim();
        if (!lowercasedQuery) {
            setFilteredArticles(allArticles);
            return;
        }
        const results = allArticles.filter(article =>
            article.title.toLowerCase().includes(lowercasedQuery) ||
            article.excerpt.toLowerCase().includes(lowercasedQuery) ||
            article.tags.some(tag => tag.toLowerCase().includes(lowercasedQuery)) ||
            article.author.name.toLowerCase().includes(lowercasedQuery)
        );
        setFilteredArticles(results);
        if (searchQuery) handleNavClick(Page.Articles);
    }, [searchQuery, allArticles]);

    // Handle smooth scrolling for single-page layout
    const handleNavClick = (page: Page) => {
        if (page === Page.Article || page === Page.Author) {
            setActivePage(page);
            return;
        }

        // If we're on a detail page, switch back to home view first
        if (activePage === Page.Article || activePage === Page.Author) {
            setSelectedArticle(null);
            setSelectedAuthor(null);
            setActivePage(Page.Home);

            // Wait for re-render before scrolling
            setTimeout(() => {
                const target = sectionRefs[page as keyof typeof sectionRefs]?.current;
                if (target) {
                    const headerOffset = 80;
                    const elementPosition = target.getBoundingClientRect().top;
                    const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
                    window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
                }
            }, 100);
        } else {
            const target = sectionRefs[page as keyof typeof sectionRefs]?.current;
            if (target) {
                const headerOffset = 80;
                const elementPosition = target.getBoundingClientRect().top;
                const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
                window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
            }
        }
    };

    const handleSelectArticle = (article: Article) => {
        setActivePage(Page.Article);
        setSelectedArticle(article);
        window.scrollTo(0, 0);
    };

    const handleSelectAuthor = (author: Author) => {
        setActivePage(Page.Author);
        setSelectedAuthor(author);
        window.scrollTo(0, 0);
    };

    const handleBackToHome = () => {
        setActivePage(Page.Home);
        setSelectedArticle(null);
        setSelectedAuthor(null);
    };

    const handleChatbotSendMessage = async (message: string) => {
        const userMessage: NovusMessage = { id: Date.now(), source: 'user', text: message };
        const loadingMessage: NovusMessage = { id: Date.now() + 1, source: 'model', isLoading: true };
        setMessages(prev => [...prev, userMessage, loadingMessage]);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `User: ${message}`,
                config: { systemInstruction: "Answer briefly." }
            });
            const modelResponse: NovusMessage = { id: Date.now() + 2, source: 'model', text: response.text };
            setMessages(prev => [...prev.slice(0, -1), modelResponse]);
        } catch (error: any) {
            setMessages(prev => [...prev.slice(0, -1), { id: Date.now(), source: 'model', text: "Error." }]);
        }
    };

    const renderMainContent = () => {
        return (
            <div className="flex flex-col gap-24 md:gap-32 pb-20">
                <section ref={sectionRefs[Page.Home]} id="home" className="relative min-h-[90vh] flex items-center justify-center overflow-hidden">
                    <Hero onNavClick={handleNavClick} />
                </section>

                <section ref={sectionRefs[Page.Mission]} id="mission" className="scroll-mt-24 px-4 sm:px-6 md:px-8 flex items-center justify-center">
                    <div className="container mx-auto max-w-5xl"><Mission /></div>
                </section>

                <section ref={sectionRefs[Page.Articles]} id="articles" className="scroll-mt-24 px-4 sm:px-6 md:px-8 flex items-center justify-center">
                    <div className="container mx-auto max-w-5xl">
                        {articlesLoading ? (
                            <div className="text-center text-gray-700 text-[10px] uppercase tracking-[0.4em] py-20">LOADING...</div>
                        ) : (
                            <Articles articles={filteredArticles} onSelectArticle={handleSelectArticle} showFilters={true} />
                        )}
                    </div>
                </section>

                {/* Global Trending moved down slightly with extra padding */}
                <section ref={sectionRefs[Page.GlobalTrending]} id="trending" className="scroll-mt-24 pt-16 md:pt-24 px-4 sm:px-6 md:px-8 flex items-center justify-center">
                    <div className="container mx-auto max-w-5xl"><GlobalTrending onSelectArticle={handleSelectArticle} /></div>
                </section>

                {/* Ecosystem brought up by reducing top padding */}
                <section ref={sectionRefs[Page.Ecosystem]} id="ecosystem" className="scroll-mt-32 pt-8 md:pt-12 px-4 sm:px-6 md:px-8 flex items-center justify-center">
                    <div className="container mx-auto max-w-7xl"><Ecosystem onNavClick={handleNavClick} /></div>
                </section>

                <section ref={sectionRefs[Page.Contact]} id="contact" className="scroll-mt-24 px-4 sm:px-6 md:px-8 flex items-center justify-center">
                    <div className="container mx-auto max-w-5xl"><Contact /></div>
                </section>
            </div>
        );
    };

    const renderDetailContent = () => {
        if (activePage === Page.Author && selectedAuthor) {
            const authorArticles = allArticles.filter(a => a.author.id === selectedAuthor.id);
            return <AuthorPage author={selectedAuthor} articles={authorArticles} onBack={handleBackToHome} onSelectArticle={handleSelectArticle} />;
        }
        if (activePage === Page.Article && selectedArticle) {
            return <ArticlePage article={selectedArticle} articles={allArticles} onBack={handleBackToHome} onSelectArticle={handleSelectArticle} onSelectAuthor={handleSelectAuthor} onAskNovusHighlight={() => {}} />;
        }
        return renderMainContent();
    };

    return (
        <div className="bg-black text-gray-100 font-sans selection:bg-red-600 selection:text-white">
            <div className="fixed top-0 left-0 w-full h-full bg-[#030303] z-0"></div>
            <Layout activePage={activePage} onNavClick={handleNavClick} searchQuery={searchQuery} onSearchChange={setSearchQuery}>
                {activePage === Page.Article || activePage === Page.Author ? renderDetailContent() : renderMainContent()}
            </Layout>
            <Chatbot isOpen={isChatbotOpen} setIsOpen={setIsChatbotOpen} messages={messages} onSendMessage={handleChatbotSendMessage} />
        </div>
    );
};

export default App;

